INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (729, 174567, 13, 544, '我们这个时代的宋词', '唐诗宋词虽好，离我们总有十万八千里之远。于是，在不经心时，留意起流行歌词。那是我们这个时代的宋词：
<br>
<br>郑华绢的《升F大调行板》，记得的是它里面的那句“如果月亮随风摇曳，我会想着你&nbsp;”。想起的是在《金锁记》里，长安看过的那轮月亮。
<br>
<br>刘若英唱的歌里，记住的是：“桅子花白花瓣，落在我蓝色百褶裙上。爱你，你轻声说，我低下头，闻见一阵芬芳，那个永恒的夜晚，十七岁仲夏，你吻我的那个夜晚，让我往后的时光。每当有感叹，总想起，当天的星光”。记住她轻轻的说：“爱情总是叫人心中充满疑惑，它是斜雨不断忧愁的晚春”。我当了她所有的专辑，最爱的还是那张《少女小渔的美丽与哀愁》。有女若英，有声若此。
<br>
<br>王菲的《暖昧》里，“从未等你的眼睛，从梦中看到苏醒，从未跟你畅游逛，怎么知道高兴会忘形，从未给你饮过冰，零度天气看风景&nbsp;，从未攀过雪山&nbsp;，所以以为天会继续晴”。听她唱：“等到风景都看透&nbsp;也许你会陪我看细水长流”。林夕的好词，原该是给她唱的�D�D�D“越美丽的东西我越不可碰”。
<br>
<br>苏慧伦的歌里，记得她勇敢的说，“我一个人住”。记得她那首《七岁的影子》：“我一直这样相信，在这一个城市里，有个和我一样的灵魂，我每天问着每一座公园和路灯，终于有那么一天，我听见有人敲门，原来是我七岁的影子，为什么你的快乐真模糊。她这样问：&nbsp;来吧，我来带你一起去远足。只过一条马路把心房裂缝补一补，温柔的风儿它将我们抱住，七岁的影子和我在草原上又唱又闹不怕老。来吧，我来带你一起去远足，只过一条马路，解救你缩小的幸福，当你的灵魂已变黑的时候，当梦想疲惫时，我带你去远足，过一条马路”。
<br>
<br>梁咏琪的歌里，记得是她自己写的《花火》：“长路若太短，花火生命更短。双手可触及你，有眼泪仍是暖”。花火，是北野武一部电影吧？一种最脆弱美丽的东西。那是梁咏琪最不俗的一首歌。
<br>
<br>张艾嘉的歌里，记得住的是《最爱》。是《那夜我们谈了一夜的生活》。是《爱情有什么道理》。太多太多。《最爱》干净的钢琴声里，她缓缓的唱“一生只爱一个人，一世只怀一种愁”。这是钟晓阳的词，那个十九岁就写了《停车暂借问》的女子。
<br>
<br>赵学而有首歌叫《细水长流》。在广东时在香港电台“海琪的天空”里听到了，顿时惊为天人，很辛苦的从网上找来MP3，如一江春水的钢琴里，赵学而的歌声喃喃流过。那么美丽美丽的歌词啊！爱极了那一句“若你双眼是深海，便已经浸没我”，还有“若有一天要被分开，我远山也踏破，你那暗涌如在叫唤我，唤我入内，怎可不奔向你”。配器都是钢琴与弦乐，背景做得很丰富。赵学而的唱功也非常好。里面好多歌都非常喜欢。象“谈一场不后悔的恋爱”，“如若今夜不下雨”，“明天是晴天吧”。那样的名字，给了亦舒，又是一个好故事。这样的词，好象充满了模糊的憧憬。可是那内里澎湃的勇气，“天空晴时，雷霆来时，它都长流”。什么也挡不住那隐隐的暗涌。&nbsp;
<br>
<br>丁薇的歌，在校园民谣风行的时候喜欢那首《断翅的蝴蝶》。三宝的曲，黄小茂的词。词写的好。&nbsp;“多年以前一晃如昨天，能再次牵你的手已是有缘，褪色的红颜黯然的双眼，美丽仍存心中你能否看见。桃花开呀，杏花落呀，种下的情呀根深绵绵。前生无缘今生又欠欠，断翅的蝴蝶飞不上天。等到今天心碎又难免，忧伤化白云飘荡在蓝天。淡淡的来去浓浓的别离，以后日子将有此情可依。桃花开呀，杏花落呀。好好地待她，好好地过呀，情肠如线，三世里系缘，&nbsp;恋恋一生此情难定”。爵士味浓浓的钢琴和曲风，让她的歌在记忆不褪色。
<br>
<br>郁冬，一个也不太出名的歌手，记住的是他一首《时光流转》：“时间原来就是这么简单&nbsp;/&nbsp;轻易的改变我们的笑脸&nbsp;/春去秋来飘落下的花瓣&nbsp;/重复在我们的身边”；是那首《北京的冬天》：“北京的冬天嘴唇变得干裂的时候，有人开始忧愁想念着过去的朋友，北风吹进来的那一天，候鸟已经飞了很远，我们的爱变成无休止的期待”。很多年前一个人在北京冬日的教室里，边看书边听那盒《红色天空》，暖气不太足，手脚很冷，窗外是北方凛冽的风，故意把教室的灯都熄了，反反复复倒带听《北京的冬天》，彼情彼景。还有那首《欧洲特快车》，他写给毛宁的歌，歌是好歌，只是给了一个讨厌的人：“我会很快的爱上别的姑娘&nbsp;，但是忘不了&nbsp;忘不了你给我的悲伤，&nbsp;我会很快的爱上别的姑娘，&nbsp;但是忘不了&nbsp;忘不了你给我的悲伤。”
<br>
<br>那英的歌里，记得的是那首《最爱这一天》里：“人群中擦肩过有多少动人的容颜，我心里不能忘只有你微笑的双眼”。好一句三千弱水只取一瓢！还有我最爱最爱的《11000公里》。又是林夕的词啊。“”
<br>
<br>忆莲的歌里，好词总是被她的声线盖过。总是不由自主被她绮丽的声音吸引，可是又怎么不被《至少还有你》里“直到感觉你的发线，有了白雪的痕迹”的轰然深情击中！
<br>
<br>许美静的歌里，记住的是她的《风的叹息》：“如果、如果、如果，&nbsp;你不能爱我，就请原谅我的寂寞，如果我还继续爱你，也请原谅我的忧郁，如果、如果、如果，我还能爱你我的忧郁却已打扰了你，就当它是、就当它是，就当它是风的叹息”。清秀的声线，如风偶过的呢喃，无名的惆怅。
<br>
<br>孙燕姿的歌里，喜欢她的《天黑黑》。初听时叹道被她那偶像的外表骗了，这首歌好听得不得了：“我爱上让我奋不顾身的一个人，我以为这就是我所追求的世界，然而横冲直撞被误解被骗，是否成人的世界背后总有残缺，我走在每天必须面对的分岔路，我怀念过去单纯美好的小幸福，爱总是让人哭让人觉得不满足，天空很大却看不大清楚，好孤独，天黑的时候，我又想起那首歌突然期待下起安静的雨，原来外婆的道理早就唱给我听，下起雨也要勇敢前进……我相信一切都会平息，我现在好想回家去，天黑黑欲落雨。”
<br>
<br>蔡健雅的歌里，记得的是她在《纪念》里，哽咽的唱道，“想念变成一条线，在时间里面漫延，长得可以把世界切成了两个面。他在春天那一边，你的秋天刚落叶、&nbsp;刚落叶。他的样子已改变，有新伴侣的气味、的气味，那一瞬间你终于发现，那曾深爱过的人&nbsp;(嗯)，早在告别的那天已消失在这个世界”。
<br>
<br>彭羚从99年以后的《一枝花》，彻底盛放了。她的声音特质发挥到淋漓尽致，她的美丽象深夏的玫瑰令人不可逼视。她唱过很多林夕作词、用亦舒的书名作歌名歌。象《要多美丽有多美丽》，象《小玩意》，象《这双手虽然小》。喜欢《给我一段仁爱路》：“如果花开了就感激，如果分开了就放弃，陪你在路上满心欢喜，是为了风景美丽，&nbsp;不是为了你。如果心开了就回忆，如果心灰了就忘记，陪你完成这一段距离，要哭泣都来不及&nbsp;。只是要求你：给我一段仁爱路的时间，给我一枝花的怀念”。能上宽带以后，我狂当了很多歌，很偶尔的当了《随身听》，一听惊艳。这么妖艳的电子乐风格，直觉这是黄耀明的作品，后来一查，果不其然。&nbsp;“榕树下面逛逛吧，头上树叶偏降下，多厌闷外面极混杂，我闭目你说话。然后慢慢我坐下，忘掉白日的废话，多洁净，浪漫的漂白，继续静听吧。当声音随心飘，我耳畔荡着玫瑰花。将声音随身听，随街逛随我吧”。
<br>
<br>张国荣的歌，象他《春光乍泄》里的形象，他是戏里戏外如一的艺人，哀艳蘼迷，伤花般怒放。记得《风继续吹》里美丽的意象：“我劝你早点归去，你说你不想归去，叫我抱着你，悠悠海风轻轻吹，冷却了野火堆。”《白发魔女传》的主题曲里，他唱道：“红颜白发，更觉璀璨。烧也烧不透，恋火烧不透，发白透。”演唱会的MTV里看到哥哥穿格子裙涂唇膏的模样，那越来越媚的眼神，越来越俏的尖下巴，可会老否？
<br>
<br>吸口气说说黄耀明，一直觉得他是肖蝴蝶的男人。早期达明一派时期的作品，记得的是：“石头记”。写词的人是迈克。是那个随笔写得出奇得好的迈克，里面的叠词用得真好：“丝丝点点计算，偏偏相差太远，兜兜转转，化作段段尘缘，纷纷扰扰作嫁，春宵恋恋变挂，真真假假，悲欢恩怨原是诈(花色香皆看化)”。迈克帮达明写过一首只有十六字的《爱煞》：“情迷意乱，露冷衾暖，浪语倾诉，无尽爱慕。”�D�D自是透骨情语。还有林夕写的《四季歌》：“红日微风催幼苗，云外归鸟知春晓，哪个爱做梦，一觉醒来，床畔蝴蝶飞走了。船在桥底轻快摇，桥上风雨知多少，半唱半和一首歌谣，湖上荷花初开了。”
<br>
<br>达明的歌亦喜欢用亦舒的书名和各种典故，信手掂来的就有亦舒的《蔷薇泡沫》、《我们不是天使》、《今夜星光灿烂》、《忽尔今夏》、《伤逝》，来自希区柯克的《后窗》，来自古典的《诸神的音乐》，来自马尔克斯的《爱在瘟疫漫延时》和《没有张扬的命案》（多巧，林夕写过《百年孤寂》），来自赵丹的电影的《马路天使》，来自三岛由纪夫的《禁色》，来自侯孝贤的电影《我们就是这样长大的》，来自村上春树的《舞吧舞吧舞吧》，来自童话的《小王子》，来自张爱玲的《半生缘》，来自大岛渚的电影《青春残酷物语》，来自费里尼的《甜美生活》。
<br>
<br>我喜欢他那首有着长长名字的《那个下午我在旧居烧信》。还有《甜美生活》里的：“听歌剧看出戏，有时翻翻传记，水晶灯下说天气，爱情这么样美不美。”这又是林夕的词，不过讽刺的是中产阶级完美又无聊的生活。他翻唱了林夕给杨千烨的那首《再见二丁目》，里面好一句“岁月长，衣裳薄”。在《万象》里看到一个叫沈胜衣的写的好文，一篇就叫“岁月长，衣裳薄”，后来听到了才知道原来是林夕的词。还有呢：“满街脚步突然静了，满天柏树突然没有动摇。这一刹我只需要，一罐热茶吧。那味道似是什么，都不紧要。唱片店内&nbsp;传来异国民谣&nbsp;，那种快乐突然被我需要。不亲切，至少不似想你般奥妙。情和调，随着怀缅，变得萧条”。他那首《情流夜中环》里，说的是亦舒笔下白领女的寂寞？“彷似一只空罐子那么落寞，彷似一串荒冷的流逝烟花，留下寂静�z忘白昼。再见这繁荣原背里有数不清空冷孤寂，夜静又再次衍出这赫赫迷城之荒，可否不理世界不要见怪，青春借贷，倾心于一�x”。黄耀明翻唱王菲的那一版《暗涌》，王菲空灵，黄耀明却是一字一字的惊心：“害怕悲剧重演，我的命中命中，越美丽的东西我越不可碰，历史在重演，这么烦嚣城中，没理由相恋可以没有暗涌。。。然后睁不开两眼看命运光临，然后天空又再涌起密云”。有人说黄耀明的歌是香港的世纪末情结，是工业废墟的华丽回声。达明的歌和亦舒的书、林夕的词，是香港给我们的美丽剪影。
<br>
<br>不说莫文蔚的《阴天》，不说《盛夏的果实》，说说她的《十二楼》。“忘了关那扇门、那扇窗，电光、石火、秋凉。孩子离开了秋千，最快要到七月再回来荡。影剧版依然沸沸扬扬，象极了枪声大作的靶场，工作了一整天只喝了一碗冷汤。日子象是道灰墙，它没有回响。”还有《爱自己》：“慢慢坐在这张依然温暖的床上，喝一杯咖啡去研究昨天的创伤，在这个时候，抹一身��胎换骨的香，觉得最需要一个属于自己的天堂”。她的声音是佻达的，美丽的，带一点自嘲。
<br>
<br>一直觉得粤语的歌词比国语的更美丽，因为它带文言味的词语与略古雅的文法，更容易填出好句。林夕历来是填粤语词比国语词出彩的。后来有次看他写的杂文，他说自己喜欢看顾城的诗，恍然大悟。我知道了“把快乐当作泡影，把露水当作床单”的来源了。
<br>&nbsp;&nbsp;', '唐诗宋词虽好，离我们总有十万八千里之远。于是，在不经心时，留意起流行歌词。那是我们这个时代的宋词：

郑华绢的《升F大调行板》，记得的是它里面的那句“如果月亮随风摇曳，我会想着你 ”。想起的是在《金锁记》里，长安看过的那轮月亮。

刘若英唱的歌里，记住的是：“桅子花白花瓣，落在我蓝色百褶裙上。爱你，你轻声说，我低下头，闻见一阵芬芳，那个永恒的夜晚，十七岁仲夏，你吻我的那个夜晚，让我往后的时光。每当有感叹，总想起，当天的星光”。记住她轻轻的说：“爱情总是叫人心中充满疑惑，它是斜雨不断忧愁的晚春”。我当了她所有的专辑，最爱的还是那张《少女小渔的美丽与哀愁》。有女若英，有声若此。

